#include <unordered_map>

string smallestEquivalentString(string s1, string s2, string baseStr) {
    unordered_map<char, char> charMap;
    for (char c1 : s1) {
        charMap[c1] = c1;
    }
    for (char c2 : s2) {
        charMap[c2] = c2;
    }

    string result = baseStr;
    for (char c : result) {
        if (charMap.find(c) != charMap.end()) {
            result = result.substr(0, result.length()) + charMap[result[result.length()] + result.substr(result.length());
        }
    }

    return result;
}
```

